const WebSocket = require('ws');

const server = new WebSocket.Server({ port: 8080 });

let players = {};

server.on('connection', (ws) => {
  const playerId = generatePlayerId();
  players[playerId] = { ws, units: [] };

  ws.on('message', (message) => {
    const command = JSON.parse(message);
    handleCommand(playerId, command);
  });

  ws.on('close', () => {
    delete players[playerId];
  });
});

function generatePlayerId() {
  return 'player_' + Math.random().toString(36).substr(2, 9);
}

function handleCommand(playerId, command) {
  switch (command.type) {
    case 'build':
      buildStructure(playerId, command.structureType, command.position);
      break;
    case 'attack':
      attackTarget(playerId, command.unitId, command.targetId);
      break;
    case 'move':
      moveUnits(playerId, command.unitIds, command.destination);
      break;
    default:
      console.log('Unknown command type:', command.type);
  }
}

